const body = $input.first().json.body || $input.first().json;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid tenantId format');
}

if (!body.typeDocument || !body.referenceDocument || body.anneeFiscale === undefined || !body.dureeConservation) {
  throw new Error('Missing required fields');
}

return [{ json: {
  tenantId: body.tenantId,
  typeDocument: body.typeDocument,
  referenceDocument: body.referenceDocument,
  anneeFiscale: body.anneeFiscale,
  dureeConservation: body.dureeConservation,
  cheminStockage: body.cheminStockage || null,
  tailleOctets: body.tailleOctets || 0
} }];

const crypto = require('crypto');
const timestamp = new Date().toISOString();
const data = $json.typeDocument + $json.referenceDocument + $json.anneeFiscale + timestamp;
const hash = crypto.createHash('sha256').update(data).digest('hex');

return {
  ...($json),
  hashIntegrite: hash,
  timestamp: timestamp
};

const dateArchivage = new Date();
const dateExpiration = new Date(dateArchivage);
dateExpiration.setFullYear(dateExpiration.getFullYear() + $json.dureeConservation);

return {
  ...($json),
  dateArchivage: dateArchivage.toISOString().split('T')[0],
  dateExpiration: dateExpiration.toISOString().split('T')[0]
};

